import React from 'react';
import { useState } from 'react';

function App() {

  let savedData = JSON.parse(localStorage.getItem("formData"));


  let [name,setName]=useState(savedData?.name, "");
  let [email,setEmail]=useState(savedData?.email,"");
  let [dept,setDept]=useState(savedData?.dept,"");
  let [isActive, setIsActive]=useState(savedData?.isActive ? true : false);

  localStorage.setItem("formData", JSON.stringify({
    name:name,
    email:email,
    dept:dept,
    isActive:isActive
  }))

  return (
    <div>
      Name: <input type="text" name="name" value={name} onChange={(e) => setName(e.target.value)} /> <br />
      Email: <input type="email" name="email" value={email} onChange={(e) => setEmail(e.target.value)} /> <br />
      Department: <input type="text" name="dept"  value={dept} onChange={(e) => setDept(e.target.value)}/> <br />
      IsActive: <input type="checkbox" name="isActive" checked={isActive} onChange={(e) => setIsActive(e.target.checked)}/>
    </div>
  )
}

export default App